#include "FreeRTOS.h"
#include "task.h"
#include "queue.h"
#include <avr/wdt.h>
#include <SPI.h> // Arduino library mismatch!

void vSPITask(void *pvParameters)
{
    for(;;)
    {
        SPI.beginTransaction(SPISettings(14000000, MSBFIRST, SPI_MODE0));
        byte val = SPI.transfer(0x55);
        vTaskDelay(pdMS_TO_TICKS(50));
    }
}

int main(void)
{
    wdt_enable(WDTO_2S);
    SPI.begin(); // Arduino SPI begin
    xTaskCreate(vSPITask, "SPI", 128, NULL, 2, NULL);
    vTaskStartScheduler();
    for(;;);
}
